var (
	uniswapV2ABI             abi.ABI
	uniswapV2ContractAddress string
)

func InitUniswapV2EventFilter(_uniswapV2ContractAddress string) {

	var err error
	uniswapV2ABI, err = abi.JSON(strings.NewReader(jsonStrUniswapV2ABI))
	if err != nil {
		logrus.Fatalf("abi.Json error:%v", err)
		os.Exit(0)
	}

	uniswapV2ContractAddress = _uniswapV2ContractAddress
}

func FilterUniswapV2Event(txHash string, eventLog *eth_types.Log, contractAddr string, height uint64, topic0, topic1, topic2, topic3 string, topicCount int) interface{} {
	if event := filterSwap(txHash, eventLog, contractAddr, height, topic0, topic1, topic2, topic3, topicCount); event != nil {
		return event
	}

	return nil
}

func filterSwap(txHash string, eventLog *eth_types.Log, contractAddr string, height uint64, topic0, topic1, topic2, topic3 string, topicCount int) *types.UniswapV2Swap {
	eventName := "Swap"

	// TODO check addr
	if !(topic0 == uniswapV2ABI.Events[eventName].ID.Hex() && topicCount == 3) {
		return nil
	}

	sender := common.HexToAddress(topic1)
	to := common.HexToAddress(topic2)

	var eventNonIndexedData struct {
		Amount0In  *big.Int
		Amount1In  *big.Int
		Amount0Out *big.Int
		Amount1Out *big.Int
	}

	if err := uniswapV2ABI.UnpackIntoInterface(&eventNonIndexedData, eventName, []byte(eventLog.Data)); err != nil {
		logrus.Fatalf("uniswapv2 UnpackIntoInterface err:%v height:%v", err, height)
		os.Exit(0)
	}

	event := &types.UniswapV2Swap{
		Pair:       common.HexToAddress(contractAddr),
		Sender:     sender,
		Amount0In:  eventNonIndexedData.Amount0In,
		Amount1In:  eventNonIndexedData.Amount1In,
		Amount0Out: eventNonIndexedData.Amount0Out,
		Amount1Out: eventNonIndexedData.Amount1Out,
		To:         to,
	}

	return event
}
